// shadcn
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";

//  ------------------------------ | TABS - DISABLED | ------------------------------  //

export function TabsDisabled() {
  return (
    <Tabs defaultValue="home">
      <TabsList>
        <TabsTrigger value="home">Home</TabsTrigger>
        <TabsTrigger value="settings" disabled>
          Disabled
        </TabsTrigger>
      </TabsList>
    </Tabs>
  );
}
